// Kafka Event Producer Service
@org.springframework.stereotype.Service
class EventProducerService {

    private final KafkaProducer<String, String> kafkaProducer;
    private static final String DEFAULT_TOPIC = "event-tracking";

    public EventProducerService(KafkaProducer<String, String> kafkaProducer) {
        this.kafkaProducer = kafkaProducer;
    }

    public RecordMetadata sendEvent(EventRequest eventRequest, Map<String, String> httpHeaders) throws Exception {
        String topic = eventRequest.getTopic() != null ? eventRequest.getTopic() : DEFAULT_TOPIC;
        String key = eventRequest.getKey();
        String value = eventRequest.getMessage();

        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, value);

        // Add standard tracking headers from HTTP request
        addHeaderIfPresent(record, httpHeaders, "tracking-id");
        addHeaderIfPresent(record, httpHeaders, "user-id");
        addHeaderIfPresent(record, httpHeaders, "correlation-id");
        addHeaderIfPresent(record, httpHeaders, "session-id");
        addHeaderIfPresent(record, httpHeaders, "source-system");
        addHeaderIfPresent(record, httpHeaders, "content-type");

        // Add any custom headers prefixed with "x-custom-" from HTTP headers
        if (httpHeaders != null) {
            httpHeaders.entrySet().stream()
                    .filter(entry -> entry.getKey().toLowerCase().startsWith("x-custom-"))
                    .forEach(entry -> record.headers().add(
                            entry.getKey(),
                            entry.getValue().getBytes(StandardCharsets.UTF_8)
                    ));
        }

        // Add user-provided headers from the request body
        if (eventRequest.getHeaders() != null) {
            eventRequest.getHeaders().forEach((headerKey, headerValue) -> {
                if (headerKey != null && headerValue != null) {
                    record.headers().add(headerKey, headerValue.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add custom metadata as headers with "meta-" prefix
        if (eventRequest.getMetadata() != null) {
            eventRequest.getMetadata().forEach((metaKey, metaValue) -> {
                if (metaKey != null && metaValue != null) {
                    record.headers().add("meta-" + metaKey, metaValue.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add system-generated headers
        record.headers().add("produced-at", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-app", "event-tracking-system".getBytes(StandardCharsets.UTF_8));

        // Generate tracking ID if not provided
        String trackingId = getHeaderValue(record.headers(), "tracking-id");
        if (trackingId == null) {
            trackingId = UUID.randomUUID().toString();
            record.headers().add("tracking-id", trackingId.getBytes(StandardCharsets.UTF_8));
        }

        Future<RecordMetadata> future = kafkaProducer.send(record, (metadata, exception) -> {
            if (exception != null) {
                System.err.println("Failed to send event to Kafka: " + exception.getMessage());
            } else {
                System.out.println("Event sent successfully - Topic: " + metadata.topic()
                        + ", Partition: " + metadata.partition()
                        + ", Offset: " + metadata.offset());
            }
        });

        return future.get();
    }

    public void sendEventAsync(EventRequest eventRequest, Map<String, String> httpHeaders) {
        try {
            String topic = eventRequest.getTopic() != null ? eventRequest.getTopic() : DEFAULT_TOPIC;
            ProducerRecord<String, String> record = new ProducerRecord<>(topic, eventRequest.getKey(), eventRequest.getMessage());

            injectAllHeaders(record, eventRequest, httpHeaders);

            kafkaProducer.send(record, (metadata, exception) -> {
                if (exception != null) {
                    System.err.println("Async send failed: " + exception.getMessage());
                } else {
                    System.out.println("Async event sent - Topic: " + metadata.topic()
                            + ", Partition: " + metadata.partition()
                            + ", Offset: " + metadata.offset());
                }
            });
        } catch (Exception e) {
            System.err.println("Error preparing async event: " + e.getMessage());
        }
    }

    public List<RecordMetadata> sendBatchEvents(List<EventRequest> events, Map<String, String> httpHeaders) throws Exception {
        List<RecordMetadata> results = new ArrayList<>();
        String batchId = UUID.randomUUID().toString();

        for (int i = 0; i < events.size(); i++) {
            EventRequest event = events.get(i);
            if (event.getHeaders() == null) {
                event.setHeaders(new HashMap<>());
            }
            event.getHeaders().put("batch-id", batchId);
            event.getHeaders().put("batch-index", String.valueOf(i));
            event.getHeaders().put("batch-size", String.valueOf(events.size()));

            RecordMetadata metadata = sendEvent(event, httpHeaders);
            results.add(metadata);
        }

        kafkaProducer.flush();
        return results;
    }

    private void injectAllHeaders(ProducerRecord<String, String> record, EventRequest eventRequest, Map<String, String> httpHeaders) {
        if (httpHeaders != null) {
            httpHeaders.forEach((key, value) -> {
                if (isAllowedHttpHeader(key)) {
                    record.headers().add(key, value.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        if (eventRequest.getHeaders() != null) {
            eventRequest.getHeaders().forEach((key, value) -> {
                if (key != null && value != null) {
                    record.headers().add(key, value.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        if (eventRequest.getMetadata() != null) {
            eventRequest.getMetadata().forEach((key, value) -> {
                if (key != null && value != null) {
                    record.headers().add("meta-" + key, value.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        record.headers().add("produced-at", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-app", "event-tracking-system".getBytes(StandardCharsets.UTF_8));

        if (getHeaderValue(record.headers(), "tracking-id") == null) {
            record.headers().add("tracking-id", UUID.randomUUID().toString().getBytes(StandardCharsets.UTF_8));
        }
    }

    private boolean isAllowedHttpHeader(String headerName) {
        String lower = headerName.toLowerCase();
        return lower.equals("tracking-id")
                || lower.equals("user-id")
                || lower.equals("correlation-id")
                || lower.equals("session-id")
                || lower.equals("source-system")
                || lower.startsWith("x-custom-");
    }

    private void addHeaderIfPresent(ProducerRecord<String, String> record, Map<String, String> httpHeaders, String headerName) {
        if (httpHeaders != null) {
            String value = httpHeaders.get(headerName);
            if (value == null) {
                value = httpHeaders.get(headerName.toLowerCase());
            }
            if (value != null) {
                record.headers().add(headerName, value.getBytes(StandardCharsets.UTF_8));
            }
        }
    }

    private String getHeaderValue(Headers headers, String key) {
        var header = headers.lastHeader(key);
        if (header != null && header.value() != null) {
            return new String(header.value(), StandardCharsets.UTF_8);
        }
        return null;
    }

    @PreDestroy
    public void shutdown() {
        if (kafkaProducer != null) {
            kafkaProducer.flush();
            kafkaProducer.close();
            System.out.println("Kafka producer closed gracefully.");
        }
    }
}

// REST Controller
@RestController
@RequestMapping("/api/events")
class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventRequest eventRequest,
            @RequestHeader Map<String, String> httpHeaders) {
        try {
            RecordMetadata metadata = eventProducerService.sendEvent(eventRequest, httpHeaders);

            String trackingId = httpHeaders.getOrDefault("tracking-id",
                    httpHeaders.getOrDefault("Tracking-Id", UUID.randomUUID().toString()));

            EventResponse response = new EventResponse(
                    "SUCCESS",
                    metadata.topic(),
                    metadata.partition(),
                    metadata.offset(),
                    trackingId,
                    metadata.timestamp()
            );

            return ResponseEntity.ok(response);
        } catch (Exception e) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setTrackingId(httpHeaders.getOrDefault("tracking-id", "unknown"));
            return ResponseEntity.internalServerError().body(errorResponse);
        }
    }

    @PostMapping("/publish-async")
    public ResponseEntity<Map<String, String>> publishEventAsync(
            @RequestBody EventRequest eventRequest,
            @RequestHeader Map<String, String> httpHeaders) {

        String trackingId = httpHeaders.getOrDefault("tracking-id", UUID.randomUUID().toString());
        eventProducerService.sendEventAsync(eventRequest, httpHeaders);

        Map<String, String> response = new HashMap<>();
        response.put("status", "ACCEPTED");
        response.put("tracking-id", trackingId);
        response.put("message", "Event submitted for async processing");

        return ResponseEntity.accepted().body(response);
    }

    @PostMapping("/publish-batch")
    public ResponseEntity<Map<String, Object>> publishBatchEvents(
            @RequestBody List<EventRequest> events,
            @RequestHeader Map<String, String> httpHeaders) {
        try {
            List<RecordMetadata> results = eventProducerService.sendBatchEvents(events, httpHeaders);

            List<Map<String, Object>> eventResults = new ArrayList<>();
            for (RecordMetadata metadata : results) {
                Map<String, Object> result = new HashMap<>();
                result.put("topic", metadata.topic());
                result.put("partition", metadata.partition());
                result.put("offset", metadata.offset());
                result.put("timestamp", metadata.timestamp());
                eventResults.add(result);
            }

            Map<String, Object> response = new HashMap<>();
            response.put("status", "SUCCESS");
            response.put("totalEvents", events.size());
            response.put("results", eventResults);

            return ResponseEntity.ok(response);
        } catch (Exception e) {
            Map<String, Object> errorResponse = new HashMap<>();
            errorResponse.put("status", "ERROR");
            errorResponse.put("message", e.getMessage());
            return ResponseEntity.internalServerError().body(errorResponse);
        }
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        Map<String, String> response = new HashMap<>();
        response.put("status", "UP");
        response.put("service", "event-tracking-producer");
        response.put("timestamp", String.valueOf(System.currentTimeMillis()));
        return ResponseEntity.ok(response);
    }
}